#include <bits/stdc++.h>
using namespace std;
const int N=10005,M=100005;
int n,m,a[N];
int tot,tot2,dfn[N],low[N],f[N],ru[N],dp[N],uu[M],vv[M];
vector<int> g[N],g2[N];
stack<int> st;
int vis[N],cnt;
void tarjan(int u)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		int v;
		while(v=st.top())
		{
			vis[v]=0;
			f[v]=u;
			st.pop();
			if(v==u) break;
			a[u]+=a[v];
		}
	}
}
int topo()
{
	queue<int> q;
	int tot=0;
	for(int i=1;i<=n;i++)
	{
		if(f[i]==i&&!ru[i])
		{
			q.push(i);
			dp[i]=a[i];
		}
	}
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g2[u].size();i++)
		{
			int v=g2[u][i];
			dp[v]=max(dp[v],dp[u]+a[v]);
			ru[v]--;
			if(ru[v]==0) q.push(v);
		}
	}
	int ans=0;
	for(int i=1;i<=n;i++)
	{
		ans=max(ans,dp[i]);
	}
	return ans;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		uu[i]=u;
		vv[i]=v;
		g[u].push_back(v);
	}
	for(int i=1;i<=n;i++)
	{
		if(!dfn[i]) tarjan(i);
	}
	for(int i=1;i<=m;i++)
	{
		int x=f[uu[i]],y=f[vv[i]];
		if(x==y) continue;
		g2[x].push_back(y);
		ru[y]++;
	}
	cout<<topo();
	return 0;
}
